import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const projectRoot = path.resolve(__dirname, '..');
const componentsDir = path.join(projectRoot, 'src/components');
const rootIndexPath = path.join(projectRoot, 'src/index.ts');
const autoHeader =
  '// Auto-generated by scripts/sync-components.mjs — do not edit manually\n';

function componentNameFromTag(tag) {
  return tag
    .split('-')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join('');
}

function findMainTsFile(dir, folderName) {
  const files = fs
    .readdirSync(dir)
    .filter((file) => file.endsWith('.ts') && file !== 'index.ts');
  const preferred = `${folderName}.ts`;
  if (files.includes(preferred)) {
    return preferred;
  }
  return files[0];
}

function parseExportClasses(content) {
  const classes = [];
  const re = /export\s+class\s+(\w+)/g;
  let match = re.exec(content);
  while (match) {
    classes.push(match[1]);
    match = re.exec(content);
  }
  return classes;
}

function collectComponentExports(dir) {
  const byFile = new Map();

  for (const file of fs.readdirSync(dir)) {
    if (!file.endsWith('.ts') || file === 'index.ts') {
      continue;
    }

    const content = fs.readFileSync(path.join(dir, file), 'utf8');
    const classes = parseExportClasses(content);
    if (classes.length === 0) {
      continue;
    }

    byFile.set(file.replace(/\.ts$/, ''), classes);
  }

  return byFile;
}

function scaffoldIndexTs(dir, folderName, mainFile) {
  const exportsByFile = collectComponentExports(dir);

  if (exportsByFile.size === 0) {
    const stem = mainFile.replace(/\.ts$/, '');
    return `import './${stem}';\n`;
  }

  return [...exportsByFile.entries()]
    .map(([stem, classes]) => `export { ${classes.join(', ')} } from './${stem}';`)
    .join('\n')
    .concat('\n');
}

function scaffoldDemoFile(folderName, tag, name) {
  const preview = `<${tag}></${tag}>`;

  return `/** @type {import('../../../demo/types.js').ComponentDemo} */
export default {
  id: '${folderName}',
  tag: '${tag}',
  name: '${name}',
  description: 'Work in progress — customize this demo.',
  icon: \`<svg class="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="4" y="4" width="16" height="16" rx="2"/></svg>\`,
  playground: {
    tag: '${tag}',
    controls: [],
    events: [],
  },
  examples: [
    {
      title: 'Default',
      description: 'Starter example — customize in demo.mjs or demo.js.',
      preview: \`${preview}\`,
      code: \`${preview}\`,
    },
  ],
  properties: [],
};
`;
}

function parseIndexExports(content) {
  const named = [];
  const namedRe = /export\s+\{\s*([^}]+)\s*\}\s+from\s+['"]([^'"]+)['"]/g;
  let match = namedRe.exec(content);
  while (match) {
    const names = match[1]
      .split(',')
      .map((part) => part.trim().split(/\s+as\s+/).pop().trim())
      .filter(Boolean);
    named.push(names);
    match = namedRe.exec(content);
  }

  const hasSideEffect = /^import\s+['"]\.\/[^'"]+['"]/m.test(content);
  return { named, hasSideEffect };
}

function generateRootIndex(componentDirs) {
  const lines = [autoHeader.trim()];

  for (const dir of componentDirs) {
    const folderName = path.basename(dir);
    const indexPath = path.join(dir, 'index.ts');
    if (!fs.existsSync(indexPath)) {
      continue;
    }

    const { named, hasSideEffect } = parseIndexExports(
      fs.readFileSync(indexPath, 'utf8'),
    );

    for (const names of named) {
      lines.push(
        `export { ${names.join(', ')} } from './components/${folderName}';`,
      );
    }

    if (hasSideEffect && named.length === 0) {
      lines.push(`import './components/${folderName}';`);
    }
  }

  return `${lines.join('\n')}\n`;
}

function listComponentDirs() {
  if (!fs.existsSync(componentsDir)) {
    return [];
  }

  return fs
    .readdirSync(componentsDir, { withFileTypes: true })
    .filter((entry) => entry.isDirectory())
    .map((entry) => path.join(componentsDir, entry.name))
    .filter((dir) =>
      fs
        .readdirSync(dir)
        .some((file) => file.endsWith('.ts') && file !== 'index.ts'),
    )
    .sort((a, b) => path.basename(a).localeCompare(path.basename(b)));
}

function isEmptyFile(filePath) {
  if (!fs.existsSync(filePath)) {
    return true;
  }

  return fs.readFileSync(filePath, 'utf8').trim().length === 0;
}

function ensureIndexTs(dir, folderName, mainFile) {
  const indexPath = path.join(dir, 'index.ts');
  if (!isEmptyFile(indexPath)) {
    return false;
  }

  fs.writeFileSync(indexPath, scaffoldIndexTs(dir, folderName, mainFile));
  console.log(`[sync] created ${path.relative(projectRoot, indexPath)}`);
  return true;
}

function ensureDemoFile(dir, folderName, tag, name) {
  const demoMjsPath = path.join(dir, 'demo.mjs');
  const demoJsPath = path.join(dir, 'demo.js');
  const demoContent = scaffoldDemoFile(folderName, tag, name);

  if (!isEmptyFile(demoMjsPath)) {
    return false;
  }

  if (!isEmptyFile(demoJsPath)) {
    return false;
  }

  const targetPath = fs.existsSync(demoJsPath) ? demoJsPath : demoMjsPath;
  fs.writeFileSync(targetPath, demoContent);
  console.log(`[sync] created ${path.relative(projectRoot, targetPath)}`);
  return true;
}

function syncComponents() {
  const componentDirs = listComponentDirs();
  let changed = false;

  for (const dir of componentDirs) {
    const folderName = path.basename(dir);
    const tag = folderName;
    const name = componentNameFromTag(tag);
    const mainFile = findMainTsFile(dir, folderName);
    if (!mainFile) {
      continue;
    }

    const indexPath = path.join(dir, 'index.ts');
    if (ensureIndexTs(dir, folderName, mainFile)) {
      changed = true;
    }

    if (ensureDemoFile(dir, folderName, tag, name)) {
      changed = true;
    }
  }

  const nextRootIndex = generateRootIndex(componentDirs);
  const currentRootIndex = fs.existsSync(rootIndexPath)
    ? fs.readFileSync(rootIndexPath, 'utf8')
    : '';

  if (currentRootIndex !== nextRootIndex) {
    fs.writeFileSync(rootIndexPath, nextRootIndex);
    console.log('[sync] updated src/index.ts');
    changed = true;
  }

  if (!changed) {
    console.log(`[sync] ${componentDirs.length} component(s) — up to date`);
  }

  return changed;
}

syncComponents();
